import Loadable from "@loadable/component";
import React from "react";
import ReactDOM from "react-dom";
import "./BootstrapCssJS.js";
import { SpinnerFlexButton as Loading } from "./components/Util";
// import { StartupJs } from "./components/Util";
import "./index.css";
import * as serviceWorker from "./serviceWorker";

console.log("window.location: ", window.location);
console.log("process.env: ", process.env);

let App;

if (window.location.hash === "") {
  App = Loadable(
    () => import("codepen.io/pl-intro-animation-w-gsap-timelinemax"),
    {
      fallback: <Loading />
    }
  );
} else {
  App = Loadable(() => import("./App"), {
    fallback: <Loading />
  });
}

let container = document.getElementById("root");

ReactDOM.unmountComponentAtNode(container);
ReactDOM.render(<App />, container);

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://bit.ly/CRA-PWA

if (process.env.REACT_APP_BUILD_TYP !== "web-extension") {
  process.env.NODE_ENV === "development"
    ? serviceWorker.unregister()
    : serviceWorker.register();
}
